import{_ as e,o as a,c as r,ag as n}from"./chunks/framework.DXGyWiRo.js";const g=JSON.parse('{"title":"Organizational Structure","description":"","frontmatter":{},"headers":[],"relativePath":"modules/organization.md","filePath":"modules/organization.md"}'),i={name:"modules/organization.md"};function o(s,t,l,d,p,h){return a(),r("div",null,[...t[0]||(t[0]=[n(`<h1 id="organizational-structure" tabindex="-1">Organizational Structure <a class="header-anchor" href="#organizational-structure" aria-label="Permalink to &quot;Organizational Structure&quot;">​</a></h1><p>The Organization module defines the structural hierarchy of your company — departments, positions, and the reporting relationships between employees. It forms the backbone of GeniusHRM, as almost every other module (employees, leave, attendance, reports) depends on the organisational structure.</p><hr><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>The Organisation module is accessible at <strong>HR Panel → Organisation</strong>. It consists of three main sections:</p><table tabindex="0"><thead><tr><th>Section</th><th>URL</th><th>Description</th></tr></thead><tbody><tr><td><strong>Departments</strong></td><td><code>/departments</code></td><td>Company divisions or teams</td></tr><tr><td><strong>Positions</strong></td><td><code>/positions</code></td><td>Job titles and roles within departments</td></tr><tr><td><strong>Org Chart</strong></td><td><code>/org-chart</code></td><td>Visual tree representation of the hierarchy</td></tr></tbody></table><hr><h2 id="departments" tabindex="-1">Departments <a class="header-anchor" href="#departments" aria-label="Permalink to &quot;Departments&quot;">​</a></h2><p>Departments represent the primary organisational units of your company — for example: Engineering, Human Resources, Finance, Marketing.</p><h3 id="creating-a-department" tabindex="-1">Creating a Department <a class="header-anchor" href="#creating-a-department" aria-label="Permalink to &quot;Creating a Department&quot;">​</a></h3><ol><li>Navigate to <strong>Organisation → Departments</strong></li><li>Click <strong>Add Department</strong></li><li>Fill in the form:</li></ol><table tabindex="0"><thead><tr><th>Field</th><th>Required</th><th>Description</th></tr></thead><tbody><tr><td><strong>Department Name</strong></td><td>Yes</td><td>Full name (e.g., <code>Engineering</code>)</td></tr><tr><td><strong>Department Code</strong></td><td>No</td><td>Short identifier (e.g., <code>ENG</code>)</td></tr><tr><td><strong>Department Head</strong></td><td>No</td><td>Select an employee as the head of this department</td></tr><tr><td><strong>Parent Department</strong></td><td>No</td><td>For nested structures (e.g., <code>Backend</code> under <code>Engineering</code>)</td></tr><tr><td><strong>Description</strong></td><td>No</td><td>Brief description of the department&#39;s function</td></tr></tbody></table><ol start="4"><li>Click <strong>Save</strong></li></ol><h3 id="editing-a-department" tabindex="-1">Editing a Department <a class="header-anchor" href="#editing-a-department" aria-label="Permalink to &quot;Editing a Department&quot;">​</a></h3><ol><li>Click the <strong>Edit</strong> icon next to the department name</li><li>Modify the desired fields</li><li>Click <strong>Update Department</strong></li></ol><div class="tip custom-block"><p class="custom-block-title">Changing Department Head</p><p>When you assign a new department head, the previous head&#39;s designation is automatically updated. The Org Chart reflects the change immediately.</p></div><h3 id="deleting-a-department" tabindex="-1">Deleting a Department <a class="header-anchor" href="#deleting-a-department" aria-label="Permalink to &quot;Deleting a Department&quot;">​</a></h3><p>Departments cannot be deleted if they have:</p><ul><li>Active employees assigned to them</li><li>Active positions linked to them</li></ul><p>To delete a department:</p><ol><li>Reassign or archive all employees in the department</li><li>Delete all positions under it</li><li>Then delete the department</li></ol><h3 id="department-hierarchy" tabindex="-1">Department Hierarchy <a class="header-anchor" href="#department-hierarchy" aria-label="Permalink to &quot;Department Hierarchy&quot;">​</a></h3><p>You can nest departments to create sub-departments:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Company</span></span>
<span class="line"><span>├── Engineering</span></span>
<span class="line"><span>│   ├── Backend</span></span>
<span class="line"><span>│   ├── Frontend</span></span>
<span class="line"><span>│   └── DevOps</span></span>
<span class="line"><span>├── Human Resources</span></span>
<span class="line"><span>├── Finance</span></span>
<span class="line"><span>└── Marketing</span></span>
<span class="line"><span>    ├── Digital</span></span>
<span class="line"><span>    └── Content</span></span></code></pre></div><p>Set the <strong>Parent Department</strong> when creating or editing a department to establish the hierarchy.</p><hr><h2 id="positions" tabindex="-1">Positions <a class="header-anchor" href="#positions" aria-label="Permalink to &quot;Positions&quot;">​</a></h2><p>Positions (also called job titles or roles) represent specific roles that exist within departments. An employee is assigned to exactly one position at any given time.</p><h3 id="creating-a-position" tabindex="-1">Creating a Position <a class="header-anchor" href="#creating-a-position" aria-label="Permalink to &quot;Creating a Position&quot;">​</a></h3><ol><li>Navigate to <strong>Organisation → Positions</strong></li><li>Click <strong>Add Position</strong></li><li>Fill in the form:</li></ol><table tabindex="0"><thead><tr><th>Field</th><th>Required</th><th>Description</th></tr></thead><tbody><tr><td><strong>Position Title</strong></td><td>Yes</td><td>Job title (e.g., <code>Senior Software Engineer</code>)</td></tr><tr><td><strong>Department</strong></td><td>Yes</td><td>Which department this position belongs to</td></tr><tr><td><strong>Position Level</strong></td><td>No</td><td>Seniority level (Junior / Mid / Senior / Lead / Manager / Director / VP / C-Level)</td></tr><tr><td><strong>Description</strong></td><td>No</td><td>Key responsibilities of this position</td></tr><tr><td><strong>Min Salary</strong></td><td>No</td><td>Salary band minimum</td></tr><tr><td><strong>Max Salary</strong></td><td>No</td><td>Salary band maximum</td></tr></tbody></table><ol start="4"><li>Click <strong>Save</strong></li></ol><h3 id="position-department-filtering" tabindex="-1">Position-Department Filtering <a class="header-anchor" href="#position-department-filtering" aria-label="Permalink to &quot;Position-Department Filtering&quot;">​</a></h3><p>In the <strong>Add/Edit Employee</strong> form, the <strong>Position</strong> dropdown automatically filters to show only positions that belong to the selected department. If you change the department, the position dropdown resets and reloads with the new department&#39;s positions.</p><p>This ensures employees are always assigned to valid department-position combinations.</p><h3 id="editing-and-deleting-positions" tabindex="-1">Editing and Deleting Positions <a class="header-anchor" href="#editing-and-deleting-positions" aria-label="Permalink to &quot;Editing and Deleting Positions&quot;">​</a></h3><ul><li>Click <strong>Edit</strong> to modify position details</li><li>Positions with active employees assigned cannot be deleted</li><li>Reassign employees before deleting a position</li></ul><hr><h2 id="reporting-structure" tabindex="-1">Reporting Structure <a class="header-anchor" href="#reporting-structure" aria-label="Permalink to &quot;Reporting Structure&quot;">​</a></h2><p>Every employee can have a <strong>Reporting Manager</strong> set on their profile. This creates the reporting hierarchy used for:</p><ul><li>Manager-level leave approvals (a manager can approve their direct reports&#39; leave)</li><li>Performance scoring (managers score their direct reports)</li><li>Org chart visualisation</li><li>Department-level report filtering</li></ul><h3 id="setting-a-reporting-manager" tabindex="-1">Setting a Reporting Manager <a class="header-anchor" href="#setting-a-reporting-manager" aria-label="Permalink to &quot;Setting a Reporting Manager&quot;">​</a></h3><ol><li>Open an employee&#39;s profile</li><li>Click <strong>Edit</strong></li><li>In the <strong>Reporting Manager</strong> field, search and select the manager</li><li>Save</li></ol><div class="warning custom-block"><p class="custom-block-title">Circular Reporting</p><p>The system prevents circular reporting relationships. If Employee A reports to Employee B, you cannot set Employee B to report to Employee A.</p></div><hr><h2 id="org-chart" tabindex="-1">Org Chart <a class="header-anchor" href="#org-chart" aria-label="Permalink to &quot;Org Chart&quot;">​</a></h2><p>The Org Chart at <code>/org-chart</code> provides a visual tree diagram of the entire reporting hierarchy.</p><h3 id="features" tabindex="-1">Features <a class="header-anchor" href="#features" aria-label="Permalink to &quot;Features&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Feature</th><th>Description</th></tr></thead><tbody><tr><td><strong>Zoom</strong></td><td>Scroll to zoom in/out of the tree</td></tr><tr><td><strong>Pan</strong></td><td>Click and drag to navigate large charts</td></tr><tr><td><strong>Node Click</strong></td><td>Click an employee node to view their profile</td></tr><tr><td><strong>Department Filter</strong></td><td>Show only a specific department subtree</td></tr><tr><td><strong>Export</strong></td><td>Download the chart as PNG or PDF</td></tr></tbody></table><h3 id="org-chart-node" tabindex="-1">Org Chart Node <a class="header-anchor" href="#org-chart-node" aria-label="Permalink to &quot;Org Chart Node&quot;">​</a></h3><p>Each node displays:</p><ul><li>Employee profile photo (or initials avatar)</li><li>Full name</li><li>Position title</li><li>Department</li></ul><p>Lines connect employees to their reporting managers.</p><hr><h2 id="department-reports-integration" tabindex="-1">Department Reports Integration <a class="header-anchor" href="#department-reports-integration" aria-label="Permalink to &quot;Department Reports Integration&quot;">​</a></h2><p>In the Reports module, all analytics (headcount, attendance, leave) can be filtered by department and position. The department and position structure defined here directly controls what filters are available in every report.</p><hr><h2 id="best-practices" tabindex="-1">Best Practices <a class="header-anchor" href="#best-practices" aria-label="Permalink to &quot;Best Practices&quot;">​</a></h2><ul><li>Define your full department structure before importing employees</li><li>Assign department heads to all departments so the org chart reflects actual reporting lines</li><li>Use position levels consistently to enable useful analytics (e.g., headcount by seniority)</li><li>Nest sub-departments only if your organisation genuinely has that hierarchy — flat structures are easier to manage for smaller teams</li></ul>`,59)])])}const m=e(i,[["render",o]]);export{g as __pageData,m as default};
